use std::thread;
use std::time::Duration;

fn simulate_work(id: u32) -> Result<u32, String> {
    if id == 3 {
        return Err("Work simulation failed for ID 3".to_string());
    }
    thread::sleep(Duration::from_millis(100));
    Ok(id * 10)
}

fn main() {
    let mut handles = vec![];

    for id in 0..5 {
        let handle = thread::spawn(move || {
            simulate_work(id)
        });
        handles.push(handle);
    }

    for handle in handles {
        match handle.join().unwrap() {
            Ok(result) => println!("Result: {}", result),
            Err(e) => println!("Error: {}", e),
        }
    }
}
```

